form:Form.form:Scripts:
		function ListClick()
{         
	// Limpia la grilla actual para pasar al Legajo-Banco Seleccionado
	Ctrl('MAIN_GRID').DelAllRows();
	Ctrl('ids').DelAllRow();   
	var i=0;      

	// Completa los parametros para hacer el qry
	var param= new NomadXML("PARAM");
	param.SetAttr("oi_registro_fc",Ctrl("LIST").GetSelectAttrValue("id"));
	param.SetAttr("f_desde",Ctrl("f_desde").GetXValue());
	param.SetAttr("f_hasta",Ctrl("f_hasta").GetXValue());                         

	// Realiza el Query para obtener los Registros FC correspondientes al Legajo-Banco seleccionado
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();
	var xmlRegistros = nSQL.GetXML(Ctrl("main").getResource("QRY_REGISTROS"), param.ToString());

    // Completa la grilla con todos los Registros FC del Legajo-Banco                                                                            
	for (registro = xmlRegistros.FirstChild(); registro != null; registro = registro.Next()) 
		{
			Ctrl('MAIN_GRID').AddNew(); 
			Ctrl('ids').AddRow().SetAttr('id', registro.GetAttr("oi_registro_fc"));         
			Ctrl('MAIN_GRID').GetCellControl('f_registro_fc',i).SetXValue(registro.GetAttr("f_registro_fc"));
			Ctrl('MAIN_GRID').GetCellControl('n_saldo',i).SetXValue(registro.GetAttr("n_saldo"));
			Ctrl('MAIN_GRID').GetCellControl('n_cant_aprob_ant',i).SetXValue(registro.GetAttr("n_cant_aprob_ant"));
			// Si esta aprobado actualiza la información del campo con la que esta guardada en la lista de aprobados
			if(Ctrl('aprobados').GetRowByAttr("id",registro.GetAttr("oi_registro_fc"))!=null) 
				{                           
				Ctrl('MAIN_GRID').GetCellControl('l_aprueba',i).SetXValue("1");
				Ctrl('MAIN_GRID').GetCellControl('n_cant_aprob',i).SetXValue(Ctrl('aprobados').GetRowByAttr("id",registro.GetAttr("oi_registro_fc")).GetAttr("n_cant_aprob"));	
				Ctrl('MAIN_GRID').GetCellControl('n_saldo',i).SetXValue(Ctrl('aprobados').GetRowByAttr("id",registro.GetAttr("oi_registro_fc")).GetAttr("n_saldo"));
				}
			i++;	
		}

}            

function OnLoad()
{
	ListClick();
}           

function Aprobar()
{           
	// Recorre la Grilla
	for(i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)
	{              
		// Revisa si figura como aprobado o no
		if(Ctrl('MAIN_GRID').GetCellXValue('l_aprueba',i)=='1')
			{  
				// Actualiza el registro en aprobados
				if(Ctrl('aprobados').GetRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString())!=null) 
					Ctrl('aprobados').GetRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString()).SetAttr('n_cant_aprob',Ctrl('MAIN_GRID').GetCellXValue('n_cant_aprob',i));
				// Agrega registro en aprobados
				else
					{
					Ctrl('aprobados').AddRow().SetAttr('id', Ctrl('ids').GetRow(i).GetAttr("id").toString());  
					Ctrl('aprobados').GetRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString()).SetAttr('n_cant_aprob',Ctrl('MAIN_GRID').GetCellXValue('n_cant_aprob',i)); 
					Ctrl('aprobados').GetRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString()).SetAttr('n_saldo',Ctrl('MAIN_GRID').GetCellXValue('n_saldo',i));
					}
			}  
					// Elimina el registro en aprobados
			else if(Ctrl('aprobados').GetRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString())!=null)
					Ctrl('aprobados').DelRowByAttr("id",Ctrl('ids').GetRow(i).GetAttr("id").toString()); 

	}       

}

function Validar()
{
	// Valida que tenga al menos un Registro FC para aprobar
	if(Ctrl('aprobados').CountRow()==0)
		{
			alert("Debe seleccionar al menos un registro para aprobar y completar la cantidad a aprobar del mismo.");
			return false;
		} 

	// Por cada registro aprobado
	for(i=0; i<Ctrl('aprobados').CountRow(); i++)
	{       
			//Si la cantidad a aprobar esta vacia
			if(Ctrl('aprobados').GetRow(i).GetAttr('n_cant_aprob')=='')
				{
					alert("Debe completar la cantidad a aprobar en todos los registros aprobados.");  
					return false;
				}
					 //Si la cantidad a aprobar es menor o igual a 0
				else if(Ctrl('aprobados').GetRow(i).GetAttr('n_cant_aprob')<=0)
						{
							alert("La cantidad a aprobar debe ser mayor a 0 en todos los registros aprobados.");  
							return false;
						} 
							//Si la cantidad a aprobar es mayor al total del registro
						else if(parseInt(Ctrl('aprobados').GetRow(i).GetAttr('n_cant_aprob'))>parseInt(Ctrl('aprobados').GetRow(i).GetAttr('n_saldo')))
								{	   
								alert("La cantidad a aprobar no debe superar al total para todos los registros aprobados.");  
								return false;
								} 

	} 

	return true;
}
